module top_module(
    input [7:0] A,
    input [7:0] B,
    input SEL,
    output reg [7:0] OUT
);wire [7:0] negB;
    wire posA = (~B) + 1;
    assign negB = posA;

    always @(*) begin
        if (SEL == 0) begin
            OUT = A + B;
        end else begin
            OUT = A + negB;
        end
    end

endmodule
